mapper.select:
select count(1)
from t3_part_instances
where part_template_id = #{part_template_id}

mapper.delete:
delete from t3_process_anomalies
where process_exec_id = #{process_exec_id}
   or quality_data_id in (
      select quality_data_id
      from t3_processing_quality_data
      where process_exec_id = #{process_exec_id}
   )

mapper.select:
select image_url
from t3_part_instances
where part_instance_id = #{part_id}

select md.device_id as device_id, md.device_id as device_code, md.device_name as device_name, md.device_type as device_type, md.device_model as device_model, md.device_status as status, md.risk_level as risk_level, md.remarks as device_desc, md.update_time as update_time from t3_manufacturing_devices md
where 1 = 1
and ( md.device_id like concat('%', #{keyword}, '%') or md.device_name like concat('%', #{keyword}, '%') or md.device_model like concat('%', #{keyword}, '%') )
and md.risk_level = #{risk_level}
order by md.update_time desc
limit #{page_size} offset #{offset}

select count(1) from t3_manufacturing_devices md where 1 = 1
and ( md.device_id like concat('%', #{keyword}, '%') or md.device_name like concat('%', #{keyword}, '%') or md.device_model like concat('%', #{keyword}, '%') )
and md.risk_level = #{risk_level}
